SELECT stations.name, statuses.status_description AS top_to_bottom_status
FROM stations
JOIN statuses ON stations.top_to_bottom_status = statuses.status_id;

SELECT s.name, s.address, s.contact_number
FROM stations AS s
WHERE s.total_escalators = (
    SELECT MAX(total_escalators) FROM stations
);

SELECT u.user_name
FROM users u
WHERE u.user_id NOT IN (
    SELECT r.generated_by
    FROM reports r
);

SELECT mr.*
FROM maintenance_records mr
WHERE mr.description LIKE '%Maintenance%';

SELECT DISTINCT completed_by
FROM maintenance_records
WHERE strftime('%w', maintenance_date) BETWEEN 1 AND 5;

SELECT station_id, AVG(passenger_count) AS average_passenger_count
FROM passenger_flow
GROUP BY station_id;

SELECT a.handled_by, COUNT(a.alert_id) AS count_of_alerts
FROM alerts a
GROUP BY a.handled_by;
